+/**
+ * Get the display color for a notification priority.
+ */
+export function getPriorityColor(priority: NotificationPriority): string {
+  switch (priority) {
+    case "urgent":
+      return "text-red-500";
+    case "high":
+      return "text-orange-500";
+    case "normal":
+      return "text-blue-500";
+    case "low":
+      return "text-gray-500";
+    default:
+      return "text-gray-500";
+  }
+}
+
+/**
+ * Get the display icon for a notification category.
+ */
+export function getCategoryIcon(category: NotificationCategory): string {
+  switch (category) {
+    case "agents":
+      return "bot";
+    case "coordination":
+      return "git-merge";
+    case "tasks":
+      return "check-square";
+    case "costs":
+      return "dollar-sign";
+    case "security":
+      return "shield";
+    case "system":
+      return "settings";
+    default:
+      return "bell";
+  }
+}
+
+/**
+ * Format a notification timestamp relative to now.
+ */
+export function formatNotificationTime(timestamp: string): string {
+  const date = new Date(timestamp);
+  const now = new Date();
+  const diffMs = now.getTime() - date.getTime();
+  const diffMins = Math.floor(diffMs / 60000);
+  const diffHours = Math.floor(diffMs / 3600000);
+  const diffDays = Math.floor(diffMs / 86400000);
+
+  if (diffMins < 1) return "Just now";
+  if (diffMins < 60) return `${diffMins}m ago`;
+  if (diffHours < 24) return `${diffHours}h ago`;
+  if (diffDays < 7) return `${diffDays}d ago`;
+
+  return date.toLocaleDateString();
+}
